	//================================================================
	/**
	 * Easy HTML5 compliant nl2br() ; Will replace new lines (\n) with HTML5 <br> instead of XHTML <br />
	 *
	 * @param STRING 		$y_code			:: The string to apply nl2br()
	 *
	 * @return STRING 						:: The formatted string
