			case 'pb': // protocol buffers
			case 'vhd': // vhdl
			case '#release': // release
			case 'license': // license
			case 'license-bsd': // license
			case 'license-gplv3': // license
			case 'changelog': // changelog
			case 'changes': // changes
			case 'readme': // license
			case 'makefile': // makefile
			case 'cmake': // cmake file
			case 'meson.build': // meson build file
			case 'mime.types': // apache
			case 'magic': // apache
			case 'manifest': // github
			case 'exports': // linux exports
			case 'fstab': // linux fstab
			case 'group': // linux group
			case 'hosts': // linux hosts
			case 'machine-id': // openbsd machine-id
			case '.htaccess': // .htaccess
			case '.htpasswd': // .htpasswd
			case '.gitignore': // git ignore
			case '.gitattributes': // git attributes
			case '.gitmodules': // git modules
			case '.properties': // properties file
			case 'pem': // PEM Certificate File
			case 'crl': // Certificate Revocation List
			case 'crt': // Certificate File
			case 'key': // Certificate Key File
			case 'keys': // Bind DNS keys
			case 'dns': // DNS Config
			case 'csp': // Content Security Policy
			case 'httph': // HTTP Header
			case 'dist': // .dist files are often configuration files which do not contain the real-world deploy-specific parameters
			case 'lock': // ex: yarn.lock
				$type = 'text/plain';
				$disp = 'attachment';
				break;
			//-------------- web images
			case 'svg':
				$type = 'image/svg+xml';
				$disp = 'inline';
				break;
			case 'png':
				$type = 'image/png';
				$disp = 'inline';
				break;
			case 'gif':
				$type = 'image/gif';
				$disp = 'inline';
				break;
			case 'jpg':
			case 'jpe':
			case 'jpeg':
				$type = 'image/jpeg';
				$disp = 'inline';
				break;
			case 'webp':
				$type = 'image/webp';
				$disp = 'inline';
				break;
			//-------------- other images
			case 'tif':
			case 'tiff':
				$type = 'image/tiff';
				$disp = 'attachment';
				break;
			case 'wmf':
				$type = 'application/x-msmetafile';
				$disp = 'attachment';
				break;
			case 'bmp':
				$type = 'image/bmp';
				$disp = 'attachment';
				break;
			//-------------- fonts
			case 'otf':
				$type = 'application/x-font-otf';
				$disp = 'attachment';
				break;
			case 'ttf':
				$type = 'application/x-font-ttf';
				$disp = 'attachment';
				break;
			case 'woff':
				$type = 'application/x-font-woff';
				$disp = 'attachment';
				break;
			case 'woff2':
				$type = 'application/x-font-woff2';
				$disp = 'attachment';
				break;
			//-------------- portable documents
			case 'pdf':
				$type = 'application/pdf';
				$disp = 'inline'; // 'attachment';
				break;
			case 'xfdf':
				$type = 'application/vnd.adobe.xfdf';
				$disp = 'attachment';
				break;
			case 'epub':
				$type = 'application/epub+zip';
				$disp = 'attachment';
				break;
			//-------------- email / calendar / addressbook
			case 'eml':
				$type = 'message/rfc822';
				$disp = 'attachment';
				break;
			case 'ics':
				$type = 'text/calendar';
				$disp = 'attachment';
				break;
			case 'vcf':
				$type = 'text/x-vcard';
				$disp = 'attachment';
				break;
			case 'vcs':
				$type = 'text/x-vcalendar';
				$disp = 'attachment';
				break;
			case 'ldif':
				$type = 'text/ldif';
				$disp = 'attachment';
				break;
			//-------------- specials
			case 'asc':
			case 'sig':
				$type = 'application/pgp-signature';
				$disp = 'attachment';
				break;
			case 'curl':
				$type = 'application/vnd.curl';
				$disp = 'attachment';
				break;
			//-------------- graphics
			case 'psd': // photoshop file
			case 'xcf': // gimp file
				$type = 'image/x-xcf';
				$disp = 'attachment';
				break;
			case 'ai': // illustrator file
			case 'eps':
			case 'ps':
				$type = 'application/postscript';
				$disp = 'attachment';
				break;
			//-------------- web video
			case 'ogg': // theora audio
			case 'oga':
				$type = 'audio/ogg';
				$disp = 'inline';
				break;
			case 'ogv': // theora video
				$type = 'video/ogg';
				$disp = 'inline';
				break;
			case 'webm': // google vp8
				$type = 'video/webm';
				$disp = 'inline';
				break;
			//-------------- other video
			case 'mpeg':
			case 'mpg':
			case 'mpe':
			case 'mpv':
			case 'mp4':
				$type = 'video/mpeg';
				$disp = 'attachment';
				break;
			case 'mpga':
			case 'mp2':
			case 'mp3':
			case 'mp4a':
				$type = 'audio/mpeg';
				$disp = 'attachment';
				break;
			case 'qt':
			case 'mov':
				$type = 'video/quicktime';
				$disp = 'attachment';
				break;
			case 'flv':
				$type = 'video/x-flv';
				$disp = 'attachment';
				break;
			case 'avi':
				$type = 'video/x-msvideo';
				$disp = 'attachment';
				break;
			case 'wm':
			case 'wmv':
			case 'wmx':
			case 'wvx':
				$type = 'video/x-ms-'.$extension;
				$disp = 'attachment';
				break;
			//-------------- flash
			case 'swf':
				$type = 'application/x-shockwave-flash';
				$disp = 'attachment';
				break;
			//-------------- data
			case 'csv': // csv comma
			case 'tab': // csv tab
				$type = 'text/csv';
				$disp = 'attachment';
				break;
			//-------------- rich text
			case 'rtf':
				$type = 'application/rtf';
				$disp = 'attachment';
				break;
			case 'abw': // Abi Word
				$type = 'application/x-abiword';
				$disp = 'attachment';
				break;
			//-------------- openoffice / libreoffice
			case 'odc':
				$type = 'application/vnd.oasis.opendocument.chart';
				$disp = 'attachment';
				break;
			case 'otc':
				$type = 'application/vnd.oasis.opendocument.chart-template';
				$disp = 'attachment';
				break;
			case 'odf':
			case 'sxm':
				$type = 'application/vnd.oasis.opendocument.formula';
				$disp = 'attachment';
				break;
			case 'otf':
				$type = 'application/vnd.oasis.opendocument.formula-template';
				$disp = 'attachment';
				break;
			case 'odg':
			case 'fodg':
			case 'sxd':
				$type = 'application/vnd.oasis.opendocument.graphics';
				$disp = 'attachment';
				break;
			case 'otg':
				$type = 'application/vnd.oasis.opendocument.graphics-template';
				$disp = 'attachment';
				break;
			case 'odi':
				$type = 'application/vnd.oasis.opendocument.image';
				$disp = 'attachment';
				break;
			case 'oti':
				$type = 'application/vnd.oasis.opendocument.image-template';
				$disp = 'attachment';
				break;
			case 'odp':
			case 'fodp':
			case 'sxi':
				$type = 'application/vnd.oasis.opendocument.presentation';
				$disp = 'attachment';
				break;
			case 'otp':
			case 'sti':
				$type = 'application/vnd.oasis.opendocument.presentation-template';
				$disp = 'attachment';
				break;
			case 'ods':
			case 'fods':
			case 'sxc':
				$type = 'application/vnd.oasis.opendocument.spreadsheet';
				$disp = 'attachment';
				break;
			case 'ots':
			case 'stc':
				$type = 'application/vnd.oasis.opendocument.spreadsheet-template';
				$disp = 'attachment';
				break;
			case 'odt':
			case 'fodt':
			case 'sxw':
				$type = 'application/vnd.oasis.opendocument.text';
				$disp = 'attachment';
				break;
			case 'ott':
			case 'stw':
				$type = 'application/vnd.oasis.opendocument.text-template';
				$disp = 'attachment';
				break;
			case 'otm':
				$type = 'application/vnd.oasis.opendocument.text-master';
				$disp = 'attachment';
				break;
			case 'oth':
				$type = 'application/vnd.oasis.opendocument.text-web';
				$disp = 'attachment';
				break;
			case 'odb':
				$type = 'application/vnd.oasis.opendocument.database';
				$disp = 'attachment';
				break;
			//-------------- ms office
			case 'doc':
			case 'dot':
				$type = 'application/msword';
				$disp = 'attachment';
				break;
			case 'docx':
			case 'dotx':
				$type = 'application/vnd.openxmlformats-officedocument.wordprocessingml.document';
				$disp = 'attachment';
				break;
			case 'xla':
			case 'xlc':
			case 'xlm':
			case 'xls':
			case 'xlt':
			case 'xlw':
				$type = 'application/vnd.ms-excel';
				$disp = 'attachment';
				break;
			case 'xlsx':
			case 'xltx':
				$type = 'application/vnd.openxmlformats-officedocument.spreadsheetml.sheet';
				$disp = 'attachment';
				break;
			case 'pot':
			case 'pps':
			case 'ppt':
				$type = 'application/vnd.ms-powerpoint';
				$disp = 'attachment';
				break;
			case 'potx':
			case 'ppsx':
			case 'pptx':
				$type = 'application/vnd.openxmlformats-officedocument.presentationml.presentation';
				$disp = 'attachment';
				break;
			case 'mdb':
				$type = 'application/x-msaccess';
				$disp = 'attachment';
				break;
			//-------------- archives
			case '7z':
				$type = 'application/x-7z-compressed';
				$disp = 'attachment';
				break;
			case 'xz':
				$type = 'application/x-xz';
				$disp = 'attachment';
				break;
			case 'tar':
				$type = 'application/x-tar';
				$disp = 'attachment';
				break;
			case 'tgz':
			case 'tbz':
				$type = 'application/x-compressed';
				$disp = 'attachment';
				break;
			case 'gz':
				$type = 'application/x-gzip';
				$disp = 'attachment';
				break;
			case 'bz2':
				$type = 'application/x-bzip2';
				$disp = 'attachment';
				break;
			case 'z':
				$type = 'application/x-compress';
				$disp = 'attachment';
				break;
			case 'zip':
				$type = 'application/zip';
				$disp = 'attachment';
				break;
			case 'rar':
				$type = 'application/x-rar-compressed';
				$disp = 'attachment';
				break;
			case 'sit':
				$type = 'application/x-stuffit';
				$disp = 'attachment';
				break;
			//-------------- executables
			case 'exe':
			case 'msi':
			case 'dll':
			case 'com':
				$type = 'application/x-msdownload';
				$disp = 'attachment';
				break;
			//-------------- others, default
			default:
				$type = 'application/octet-stream';
				$disp = 'attachment';
			//--------------
		} //end switch
		//--
		if($ydisposition === false) {
			//--
			return (string) $type; // mime type
			//--
		} else {
			//--
			switch((string)$ydisposition) {
				case 'inline':
					$disp = 'inline'; // rewrite display mode
					break;
				case 'attachment':
					$disp = 'attachment'; // rewrite display mode
					break;
				default:
					// nothing
			} //end switch
			//--
			return array(
				(string) $type, // mime type
				(string) $disp.'; filename="'.Smart::safe_filename((string)$file, '-').'"', // mime header disposition suffix
				(string) $disp // mime disposition
			);
			//--
		} //end if else
		//--
	} //END FUNCTION
	//================================================================


} //END CLASS


//=====================================================================================
//===================================================================================== CLASS END
//=====================================================================================



