.ux-menubar-bar .ux-menubar-button {
	white-space:normal;
}
.ux-menubar-bar-block .ux-menubar-bar-item {
	width:100%;
	display:block;
	padding:9px 16px;
	text-align:left;
	border:none;
	outline:none;
	white-space:normal;
	float:none;
}
.ux-menubar-bar-block .ux-menubar-center .ux-menubar-bar-item {
	text-align:center;
}
.ux-menubar-block {
	display:block;
	width:100%;
}

