/*** Menus ***/

/** Menus, Core **/

.ux-menu {
	box-sizing: border-box;
	-moz-box-sizing: border-box !important;
	-webkit-box-sizing: border-box !important;
}

.ux-menu-fixed {
	position: fixed;
	left: 0;
	top: 0;
	z-index: 3;
}

.ux-menu-list,
.ux-menu-item {
	position: relative;
}

.ux-menu-list {
	list-style: none;
	margin: 0;
	padding: 0;
}

.ux-menu-item {
	padding: 0;
	margin: 0;
	height: 100%;
	list-style: none;
}

.ux-menu-link,
.ux-menu-heading {
	display: block;
	text-decoration: none;
	white-space: nowrap;
}

.ux-menu-link:hover {
	color: #000000 !important;
	background-color: #FFFFFF!important;
}

/** Menus, Horizontal **/

.ux-menu-horizontal {
	width: 100%;
	white-space: nowrap;
}

.ux-menu-horizontal .ux-menu-list {
	display: inline-block;
}

/* Initial menus should be inline-block so that they are horizontal */
.ux-menu-horizontal .ux-menu-item,
.ux-menu-horizontal .ux-menu-heading,
.ux-menu-horizontal .ux-menu-separator {
	display: inline-block;
	*display: inline;
	vertical-align: middle;
}

/** Menus, Styling **/

/* misc default styling */

.ux-menu-separator {
	background-color: #cccccc;
	height: 1px;
	margin: 0.3rem 0;
}

.ux-menu-horizontal .ux-menu-separator {
	width: 1px;
	height: 1.3rem;
	margin: 0 0.3rem;
}

.ux-menu-heading {
	cursor: default;
	font-weight: bold;
	text-transform: uppercase;
	color: #565d64;
}

.ux-menu-link {
	color: #777777;
}

.ux-menu-children {
	background-color: #ffffff;
}

.ux-menu-link,
.ux-menu-disabled,
.ux-menu-heading {
	padding: 0.5rem 1rem;
}

.ux-menu-disabled {
	opacity: 0.5;
}

.ux-menu-disabled .ux-menu-link:hover {
	background-color: transparent;
}

.ux-menu-active > .ux-menu-link,
.ux-menu-link:hover,
.ux-menu-link:focus {
	background-color: #eeeeee;
}

.ux-menu-selected .ux-menu-link,
.ux-menu-selected .ux-menu-link:visited {
	color: #000000;
}

/*** Responsive NavBar Menu (by Unixman) ***/

nav.ux-navbar label.toggle,
nav.ux-navbar input[id^=drop] {
	display: none;
}
nav.ux-navbar {
	margin: 0;
	padding: 0;
	background-color: #3f51b5;
}
nav.ux-navbar span.detail-s {
	display: none;
}
nav.ux-navbar span.detail-l {
	display: inline;
}
nav.ux-navbar div#logo {
	display: block;
	padding: 0 25px;
	float: left;
	font-size: 20px;
	line-height: 50px;
	color: #FFFFFF;
	cursor: default;
}
nav.ux-navbar label#alt-logo {
	font-weight: bold;
}
nav.ux-navbar img#img-logo {
	display: block;
	float: left;
	margin-top: 1px;
	width: 48px;
	height: 48px;
}
nav::after {
	content: "";
	display: table;
	clear: both;
}
nav.ux-navbar ul {
	float: right;
	padding: 0;
	margin: 0;
	list-style: none;
	position: relative;
}
nav.ux-navbar li.parent {
	display: none;
}
nav.ux-navbar ul li {
	margin: 0px;
	display: inline-block;
	float: left;
	background-color: #3f51b5;
}
nav.ux-navbar a, nav.ux-navbar label.notoggle {
	display: block;
	padding: 0 20px;
	color: #FFFFFF;
	font-size: 20px;
	line-height: 50px;
	text-decoration: none;
}
nav.ux-navbar ul li ul li:hover {
	background-color: #2e40a4;
}
nav.ux-navbar a:hover {
	color: #FFFFFF;
	background-color: #1d3093;
}
nav.ux-navbar ul ul {
	display: none;
	position: absolute;
	top: 50px;
	z-index: 5555;
}
nav.ux-navbar ul li:hover > ul {
	display: inherit;
}
nav.ux-navbar ul ul li {
	min-width: 170px;
	float: none;
	display: list-item;
	position: relative;
}
nav.ux-navbar ul ul ul {
	min-width: 170px;
	width: 100%;
	position: absolute;
	top: 10px;
	left: 170px;
}
nav.ux-navbar ul ul ul li {
	position: relative;
}
nav.ux-navbar li > a::after {
	content: ' ▾';
}
nav.ux-navbar li > a:only-child::after {
	content: '';
}

nav.ux-navbar.navbar-green {
	background-color: #6a9d4e;
}
nav.ux-navbar.navbar-green ul li {
	background-color: #6a9d4e;
}
nav.ux-navbar.navbar-green ul li ul li:hover {
	background-color: #598c3d;
}
nav.ux-navbar.navbar-green a:hover {
	background-color: #487b2c;
}

nav.ux-navbar.navbar-black {
	background-color: #3b4250;
}
nav.ux-navbar.navbar-black ul li {
	background-color: #3b4250;
}
nav.ux-navbar.navbar-black ul li ul li:hover {
	background-color: #2a3140;
}
nav.ux-navbar.navbar-black a:hover {
	background-color: #192030;
}

/*** BreadCrumbs (by Unixman) ***/

/* Style the list */
ul.ux-breadcrumb {
	padding: 10px 16px !important;
	list-style: none !important;
	background-color: #eee !important;
}

/* Display list items side by side */
ul.ux-breadcrumb li {
	display: inline !important;
	font-size: 1rem !important;
	color: #6C757D !important;
	font-weight: bold !important;
}

/* Add a slash symbol (/) before/behind each list item */
ul.ux-breadcrumb li+li::before {
	padding: 8px !important;
	color: #6C757D !important;
	font-weight: bold !important;
	content: "/\00a0" !important;
}

/* Add a color to all links inside the list */
ul.ux-breadcrumb li a {
	color: #0275d8 !important;
	text-decoration: none !important;
	font-weight: bold !important;
}

/* Add a color on mouse-over */
ul.ux-breadcrumb li a:hover {
	color: #01447e !important;
	text-decoration: underline !important;
	font-weight: bold !important;
}

/*** DropDown (by Unixman) ***/

div.ux-dropdown {
	cursor: pointer;
	display: inline-block; /* do not mark as important as it can't hide using jquery hide() */
	margin-bottom: 5px;
	margin-right: 5px;
}

div.ux-dropdown span.ux-dropbutton::before,
div.ux-dropdown span.ux-droparea::before {
	content: '▾ ';
	right: 0px;
	top: 0px;
	width: 1.5rem;
	height: 50%;
	font-size: 1rem !important;
}

div.ux-dropdown span.ux-dropbutton {
	display: inline-block; /* do not mark as important as it can't hide using jquery hide() */
	padding: 7px 15px 7px 15px !important;
	line-height: normal !important;
	white-space: nowrap !important;
	vertical-align: middle !important;
	text-align: center !important;
	font-family: inherit !important;
	font-size: 1rem !important;
	font-weight: bold !important;
	text-decoration: none !important;
	border-radius: 3px !important;
	border: 1px solid #90979d !important;
	background-color: #6c757d !important;
	color: #FFFFFF !important;
	cursor: pointer !important;
	overflow: hidden;
	text-overflow: ellipsis;
	margin-bottom: 0px;
	margin-right: 0px;
	box-sizing: border-box !important;
	-moz-box-sizing: border-box !important;
	-webkit-box-sizing: border-box !important;
	appearance: none !important;
	-moz-appearance: none !important;
	-webkit-appearance: none !important;
	user-select: none !important;
}

div.ux-dropdown ul {
	z-index: 5555;
	visibility: hidden;
	opacity: 0;
	background: #FFFFFF;
	margin: 0;
	padding: 5px 10px 10px 5px;
	display: block;
	position: absolute;
	min-width: 1px;
	max-width: 1px;
	height: 1px;
	transform: translateY(-25px);
}

div.ux-dropdown:hover ul {
	visibility: visible;
	opacity: 1;
	border: 1px solid #dde1e9;
	cursor: default;
	min-width: 125px;
	max-width: 300px;
	height: auto;
	border-radius: 1px;
	transform: translateY(0);
}

div.ux-dropdown ul li {
	display: block;
	float: none;
	width: 100%;
	text-align: left;
	margin: 0;
	padding: 8px 0 0 16px;
	line-height: 1.5;
	color: #8b939c;
}

div.ux-dropdown ul li a:not(.ux-button) {
	color: #ee4b34;
	padding: 0 10px;
	line-height: 1.5;
	text-decoration: none !important;
	border-bottom: 0px !important;
}
div.ux-dropdown ul li a:not(.ux-button):hover {
	text-decoration: underline !important;
	border-bottom: 0px !important;
}

/*** Collapsible (by Unixman) ***/

.ux-collapse div.tab {
	position: relative;
	margin-bottom: 0;
	width: 100%;
	overflow: hidden;
}
.ux-collapse div.tab input {
	position: absolute;
	opacity: 0;
	z-index: -1;
}
.ux-collapse div.tab label {
	color: #111111;
	background-color: #F7F7F7;
	border: 1px solid #ededed;
	border-bottom: 0 !important;
	position: relative;
	display: block;
	padding: 0 0 0 1em;
	font-weight: bold;
	line-height: 3;
	cursor: pointer;
}
.ux-collapse div.tab div.tab-content {
	color: #111111;
	background-color: #FCFCFC;
	border: 1px solid #ededed;
	border-top: 0 !important;
	max-height: 0;
	overflow: hidden;
	transition: max-height .35s;
}
.ux-collapse div.tab:not(:last-child) div.tab-content {
	border-bottom: 0 !important;
}
.ux-collapse div.tab div.tab-content p {
	margin: 1em;
}
.ux-collapse div.tab input:checked ~ div.tab-content {
	max-height: 100vh;
}
.ux-collapse div.tab label::after {
	position: absolute;
	right: 0;
	top: 0;
	display: block;
	width: 3em;
	height: 3em;
	line-height: 3;
	text-align: center;
	transition: all .35s;
}
.ux-collapse div.tab input[type=checkbox] + label::after {
	content: "+";
}
.ux-collapse div.tab input[type=radio] + label::after {
	content: "\25BC";
}
.ux-collapse div.tab input[type=checkbox]:checked + label::after {
	transform: rotate(315deg);
}
.ux-collapse div.tab input[type=radio]:checked + label::after {
	transform: rotateX(180deg);
}

.ux-collapse.dark div.tab label {
	color: #FFFFFF;
	background-color: #333333;
	border: 1px solid #222222;
}
.ux-collapse.dark div.tab .tab-content {
	color: #FFFFFF;
	background-color: #555555;
	border: 1px solid #222222;
}

/*** Bars (by Unixman) ***/

.ux-section {
	color: #3C4663 !important;
	background: #FFFFFF !important;
	border: 1px solid #6C757D;
	display: block;
	padding: 7px !important;
	padding-left: 15px !important;
	padding-right: 15px !important;
	margin-bottom: 25px !important;
	border-radius: 2px;
}

.ux-subsection {
	color: #FFFFFF !important;
	background: #3C4663 !important;
	border: 1px solid #6D748C;
	display: block;
	padding: 5px !important;
	padding-left: 10px !important;
	padding-right: 10px !important;
	margin-bottom: 25px !important;
	border-radius: 2px;
}

/*** Steps Bar (by Unixman) ***/

.ux-stepsbar {
	/*centering*/
	display: inline-block;
	box-shadow: 0 0 15px 1px rgba(0, 0, 0, 0.35);
	overflow: hidden;
	border-radius: 5px;
	/*Lets add the numbers for each link using CSS counters. flag is the name of the counter. to be defined using counter-reset in the parent element of the links*/
	counter-reset: flag;
}

.ux-stepsbar a {
	text-decoration: none;
	outline: none;
	display: block;
	float: left;
	font-size: 0.9rem;
	line-height: 2.3rem !important;
	color: #FFFFFF !important;
	/*need more margin on the left of links to accomodate the numbers*/
	padding: 0 10px 0 60px;
	background: #666666;
	position: relative;
}
/* since the first link does not have a triangle before it we can reduce the left padding to make it look consistent with other links */
.ux-stepsbar a:first-child {
	padding-left: 46px;
	border-radius: 5px 0 0 5px; /*to match with the parent's radius*/
}
.ux-stepsbar a:first-child::before {
	left: 14px;
}
.ux-stepsbar a:last-child {
	border-radius: 0 5px 5px 0; /*this was to prevent glitches on hover*/
	padding-right: 20px;
}

/* hover/active styles */
.ux-stepsbar a.active, .ux-stepsbar a:hover{
	background: #333333;
}
.ux-stepsbar a.active::after, .ux-stepsbar a:hover::after {
	background: #333333;
}

/* adding the arrows for the steps bar using rotated pseudo elements */
.ux-stepsbar a::after {
	content: '';
	position: absolute;
	top: 0;
	right: -18px; /*half of square's length*/
	/*same dimension as the line-height of .ux-stepsbar a */
	width: 36px;
	height: 36px;
	/*as you see the rotated square takes a larger height. which makes it tough to position it properly. So we are going to scale it down so that the diagonals become equal to the line-height of the link. We scale it to 70.7% because if square's:
	length = 1; diagonal = (1^2 + 1^2)^0.5 = 1.414 (pythagoras theorem)
	if diagonal required = 1; length = 1/1.414 = 0.707*/
	transform: scale(0.707) rotate(45deg);
	/*we need to prevent the arrows from getting buried under the next link*/
	z-index: 1;
	/*background same as links but the gradient will be rotated to compensate with the transform applied*/
	background: #666666;
	/*stylish arrow design using box shadow*/
	box-shadow:
		2px -2px 0 2px rgba(0, 0, 0, 0.4),
		3px -3px 0 2px rgba(255, 255, 255, 0.1);
		/* 5px - for rounded arrows and 50px - to prevent hover glitches on the border created using shadows */
	border-radius: 0 5px 0 50px;
}
/* dont need an arrow after the last link */
.ux-stepsbar a:last-child::after {
	content: none;
}
/* will use the ::before element to show numbers */
.ux-stepsbar a::before {
	text-align: center;
	content: counter(flag);
	counter-increment: flag;
	/*some styles now*/
	border-radius: 100%;
	width: 20px;
	height: 20px;
	line-height: 20px;
	margin: 8px 0;
	position: absolute;
	top: 0;
	left: 30px;
	background: #444444;
	font-weight: bold;
}

.ux-stepsbar-light a {
	color: #333333 !important;
}
.ux-stepsbar-light a, .ux-stepsbar-light a::after {
	background: #FFFFFF;
	color: #000000;
	transition: all 0.5s;
}
.ux-stepsbar-light a::before {
	background: #FFFFFF;
	box-shadow: 0 0 0 1px #CCCCCC;
}
.ux-stepsbar-light a:hover, .ux-stepsbar-light a.active,
.ux-stepsbar-light a:hover::after, .ux-stepsbar-light a.active::after{
	background: #BBBBBB;
}

/***** END *****/

