	const sha512 = function(s) {
		//--
		if(testCryptoHash_SHA512 !== true) { // run test
			if(sha512_hex(_Test$.unicodeString()) == _Test$.testSHA512()) {
				testCryptoHash_SHA512 = true; // test passed
