	width: 35vw;
	max-width: 960px;
	background: #FFFFFF;
	border-radius: 4px;
	padding: 20px;
	margin: 0 auto;
	min-height: 100px;
	height: 25vh;
	max-height: 720px;
	border: 1px solid #F2F2F2;
}

/* Overlay */
.alertable-overlay {
	position: fixed;
	z-index: 2147482004;
	top: 0;
	right: 0;
	bottom: 0;
	left: 0;
	background: rgba(238, 238, 238, 0.55);
}

/* Form */
.alertable-form {
	width: 100%;
	height: 100%;
}

/* Message */
.alertable-message {
	padding: 5px;
	margin-bottom: 20px;
	white-space: pre-wrap;
	height: calc(100% - 40px);
	overflow-y: auto;
	overflow-x: hidden;
}
.alertable-message-html {
	white-space: normal !important;
}

/* Prompt */
.alertable-prompt {
	margin-bottom: 20px;
}

.alertable-input {
	width: 100%;
	border-radius: 4px;
	box-shadow: none;
	border: solid 1px #ccc;
	font-family: inherit;
	font-size: inherit;
	color: inherit;
	padding: 6px 12px;
	display: block;
	box-sizing: border-box;
	margin-bottom: 10px;
}

/* Button group */
.alertable-buttons {
	position: absolute; /* for old browsers */
	bottom: 10px;
	right: 10px;
	text-align: right;
}

/* OK button */
.alertable-ok {
/*
	background: #09d;
	border: solid 1px #09d;
	color: white;
*/
	background: #FFFFFF;
	border: solid 1px #DDDDDD;
	color: #333333;
	font-family: inherit;
	font-size: inherit;
	border-radius: 3px;
	padding: 6px 12px;
	margin-left: 10px;
	cursor: pointer;
}

.alertable-ok:hover,
.alertable-ok:focus,
.alertable-ok:active {
/*	background-color: #08c; */
	background-color: #DCDCDC;
	outline: none;
}
.alertable-ok::-moz-focus-inner { /* disable mozilla focus selector as dotted border */
	border: 0 !important;
}

/* Cancel button */
.alertable-cancel {
	border: solid 1px #DDDDDD;
	background: #FFFFFF;
	font-family: inherit;
	font-size: inherit;
	color: #888888;
	border-radius: 3px;
	padding: 6px 12px;
	margin-left: 10px;
	cursor: pointer;
}

.alertable-cancel:hover,
.alertable-cancel:focus,
.alertable-cancel:active {
	background-color: #f2f2f2;
}

/* END */

</style>
HTML;
