			ctx.scale(0.4, 0.4);
			ctx.rotate(-Math.PI / 2);
			ctx.strokeStyle = '#444444';
			ctx.fillStyle = '#FFFFFF';
			ctx.lineWidth = 8;
			ctx.lineCap = 'round';
			// Hour marks
			ctx.save();
			let i;
			for(i=0; i<12; i++) {
				switch(i) {
					case 2: // 3
					case 5: // 6
					case 8: // 9
					case 11: // 12
						ctx.strokeStyle = '#ED2839';
						break;
					default:
						ctx.strokeStyle = '#333333';
				}
				ctx.beginPath();
				ctx.rotate(Math.PI / 6);
				ctx.moveTo(100, 0);
				ctx.lineTo(120, 0);
				ctx.stroke();
			}
			ctx.restore();
			// Minute marks
			ctx.save();
			ctx.lineWidth = 5;
			for(i=0; i<60; i++) {
				if(i % 5!= 0) {
					ctx.beginPath();
					ctx.moveTo(117, 0);
					ctx.lineTo(120, 0);
					ctx.stroke();
				}
				ctx.rotate(Math.PI / 30);
			}
			ctx.restore();
			let sec = now.getSeconds();
			let mins = now.getMinutes();
			let hr  = now.getHours();
			hr = hr >= 12 ? hr - 12 : hr;
			ctx.fillStyle = '#222222';
			// write Hours
			ctx.save();
			ctx.rotate(hr * (Math.PI / 6) + (Math.PI / 360) * mins + (Math.PI / 21600) *sec);
			ctx.lineWidth = 14;
			ctx.beginPath();
			ctx.moveTo(-20, 0);
			ctx.lineTo(80, 0);
			ctx.stroke();
			ctx.restore();
			// write Minutes
			ctx.save();
			ctx.rotate((Math.PI / 30) * mins + (Math.PI / 1800) * sec);
			ctx.lineWidth = 10;
			ctx.beginPath();
			ctx.moveTo(-28, 0);
			ctx.lineTo(112, 0);
			ctx.stroke();
			ctx.restore();
			// Write seconds
			ctx.save();
			ctx.rotate(sec * Math.PI / 30);
			ctx.strokeStyle = '#ED2839';
			ctx.fillStyle = '#ED2839';
			ctx.lineWidth = 6;
			ctx.beginPath();
			ctx.moveTo(-30, 0);
			ctx.lineTo(83, 0);
			ctx.stroke();
			ctx.beginPath();
			ctx.arc(0, 0, 10, 0, Math.PI * 2, true);
			ctx.fill();
			ctx.beginPath();
			ctx.arc(95, 0, 10, 0, Math.PI * 2, true);
			ctx.stroke();
			ctx.fillStyle = 'rgba(0, 0, 0, 0)';
			ctx.arc(0, 0, 3, 0, Math.PI * 2, true);
			ctx.fill();
			ctx.restore();
			ctx.beginPath();
			ctx.lineWidth = 7;
			ctx.strokeStyle = '#555555';
			ctx.arc(0, 0, 142, 0, Math.PI * 2, true);
			ctx.stroke();
			ctx.restore();
			// handle animation
			animate(watch);
		};
		// start animation
		animate(watch);
	};
	WatchClock();
} // prevent run this more than once
</script>
<!-- #END :: Partial Template: Core.WatchClock -->
